SELECT AVG(awardsshareplayers.pointsWon) AS average_points_won_by_all_star_players FROM awardsplayers JOIN awardsshareplayers ON awardsplayers.playerID = awardsshareplayers.playerID AND awardsplayers.yearID = awardsshareplayers.yearID AND awardsplayers.lgID = awardsshareplayers.lgID JOIN allstarfull ON awardsplayers.playerID = allstarfull.playerID AND awardsplayers.yearID = allstarfull.yearID WHERE awardsplayers.awardID = 'TSN All-Star';